// Welcome.js
import React from 'react';
import Grid from '@material-ui/core/Grid';
import Typography from '@material-ui/core/Typography';
import useStyles from './styles';
import Soccer1 from '../../../images/soccer1.png';
import Soccer2 from '../../../images/soccer2.png';

const Welcome = () => {
  const classes = useStyles();

  return (
    <div className={classes.outerContainer}>
      {/* Vänster sida */}
      <Grid container spacing={1} className={classes.leftContainer}>
        <Grid item xs={12}>
          {/* Övre bild */}
          <div className={classes.imageContainer}>
            <img className={classes.image} src={Soccer2} alt="Stående bild" />
          </div>
        </Grid>
        <Grid item xs={12}>
          {/* Undre bild */}
          <div className={`${classes.imageContainer} ${classes.overlappingImage}`}>
            <img className={classes.image} src={Soccer1} alt="Liggande bild" />
          </div>
        </Grid>
      </Grid>

      {/* Höger sida */}
      <Grid item xs={12} sm={6} className={classes.rightContainer}>
        {/* Textsektion */}
        <div className={classes.textContainer}>
          <Typography variant="h6" gutterBottom>
            Din text här
          </Typography>
          <Typography variant="body1">
            Mer text här...
          </Typography>
        </div>
      </Grid>
    </div>
  );
};

export default Welcome;
